127: Http::FilterHeadersStatus HeaderToMetadataFilter::decodeHeaders(Http::RequestHeaderMap& headers,
128:                                                                 bool) {
129:   const auto* config = getConfig();
130:   if (config->doRequest()) {
131:     writeHeaderToMetadata(headers, config->requestRules(), *decoder_callbacks_);
132:   }
133: 
134:   return Http::FilterHeadersStatus::Continue;
135: }
