156: bool HeaderToMetadataFilter::addMetadata(StructMap& struct_map, const std::string& meta_namespace,
157:                                          const std::string& key, std::string value, ValueType type,
158:                                          ValueEncode encode) const {
159:   ProtobufWkt::Value val;
160: 
161:   ASSERT(!value.empty());
162: 
163:   if (value.size() >= MAX_HEADER_VALUE_LEN) {
164:     // Too long, go away.
165:     ENVOY_LOG(debug, "metadata value is too long");
166:     return false;
167:   }
168: 
169:   if (encode == envoy::extensions::filters::http::header_to_metadata::v3::Config::BASE64) {
170:     value = Base64::decodeWithoutPadding(value);
171:     if (value.empty()) {
172:       ENVOY_LOG(debug, "Base64 decode failed");
173:       return false;
174:     }
175:   }
176: 
177:   // Sane enough, add the key/value.
178:   switch (type) {
179:     PANIC_ON_PROTO_ENUM_SENTINEL_VALUES;
180:   case envoy::extensions::filters::http::header_to_metadata::v3::Config::STRING:
181:     val.set_string_value(std::move(value));
182:     break;
183:   case envoy::extensions::filters::http::header_to_metadata::v3::Config::NUMBER: {
184:     double dval;
185:     if (absl::SimpleAtod(StringUtil::trim(value), &dval)) {
186:       val.set_number_value(dval);
187:     } else {
188:       ENVOY_LOG(debug, "value to number conversion failed");
189:       return false;
190:     }
191:     break;
192:   }
193:   case envoy::extensions::filters::http::header_to_metadata::v3::Config::PROTOBUF_VALUE: {
194:     if (!val.ParseFromString(value)) {
195:       ENVOY_LOG(debug, "parse from decoded string failed");
196:       return false;
197:     }
198:     break;
199:   }
200:   }
201: 
202:   auto& keyval = struct_map[meta_namespace];
203:   (*keyval.mutable_fields())[key] = std::move(val);
204: 
205:   return true;
206: }
207: 
208: const std::string& HeaderToMetadataFilter::decideNamespace(const std::string& nspace) const {
209:   return nspace.empty() ? HttpFilterNames::get().HeaderToMetadata : nspace;
210: }
211: 
212: // add metadata['key']= value depending on header present or missing case
213: void HeaderToMetadataFilter::applyKeyValue(std::string&& value, const Rule& rule,
214:                                            const KeyValuePair& keyval, StructMap& np) {
215:   if (!keyval.value().empty()) {
216:     value = keyval.value();
217:   } else {
218:     const auto& matcher = rule.regexRewrite();
219:     if (matcher != nullptr) {
220:       value = matcher->replaceAll(value, rule.regexSubstitution());
221:     }
222:   }
223:   if (!value.empty()) {
224:     const auto& nspace = decideNamespace(keyval.metadata_namespace());
225:     addMetadata(np, nspace, keyval.key(), value, keyval.type(), keyval.encode());
226:   } else {
227:     ENVOY_LOG(debug, "value is empty, not adding metadata");
228:   }
229: }
230: 
231: void HeaderToMetadataFilter::writeHeaderToMetadata(Http::HeaderMap& headers,
232:                                                    const HeaderToMetadataRules& rules,
233:                                                    Http::StreamFilterCallbacks& callbacks) {
234:   StructMap structs_by_namespace;
235: 
236:   for (const auto& rule : rules) {
237:     const auto& proto_rule = rule.rule();
238:     absl::optional<std::string> value = rule.selector_->extract(headers);
239: 
240:     if (value && proto_rule.has_on_header_present()) {
241:       applyKeyValue(std::move(value).value_or(""), rule, proto_rule.on_header_present(),
242:                     structs_by_namespace);
243:     } else if (!value && proto_rule.has_on_header_missing()) {
244:       applyKeyValue(std::move(value).value_or(""), rule, proto_rule.on_header_missing(),
245:                     structs_by_namespace);
246:     }
247:   }
248:   // Any matching rules?
249:   if (!structs_by_namespace.empty()) {
250:     for (auto const& entry : structs_by_namespace) {
251:       callbacks.streamInfo().setDynamicMetadata(entry.first, entry.second);
252:     }
253:   }
254: }
255: 
256: // TODO(rgs1): this belongs in one of the filter interfaces, see issue #10164.
257: const Config* HeaderToMetadataFilter::getConfig() const {
258:   // Cached config pointer.
259:   if (effective_config_) {
260:     return effective_config_;
261:   }
262: 
263:   effective_config_ = Http::Utility::resolveMostSpecificPerFilterConfig<Config>(decoder_callbacks_);
264:   if (effective_config_) {
265:     return effective_config_;
266:   }
267: 
268:   effective_config_ = config_.get();
269:   return effective_config_;
270: }
271: 
272: } // namespace HeaderToMetadataFilter
273: } // namespace HttpFilters
274: } // namespace Extensions
275: } // namespace Envoy
