150: 
151:   maybeInitializeRouteConfigs(decoder_callbacks_);
152: 
153:   for (const PerRouteHeaderMutation& route_config : route_configs_) {
154:     route_config.mutations().mutateRequestHeaders(headers, context,
155:                                                   decoder_callbacks_->streamInfo());
156:   }
