using testing::NiceMock;

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {
namespace {

class CustomHeaderInjectionTest : public testing::Test {
public:
  void initializeFilter(const std::string& yaml) {
    envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection config;
    TestUtility::loadFromYaml(yaml, config);
    config_ = std::make_shared<CustomHeaderInjectionConfig>(config);
    filter_ = std::make_shared<CustomHeaderInjectionFilter>(config_);
    filter_->setDecoderFilterCallbacks(decoder_callbacks_);
    filter_->setEncoderFilterCallbacks(encoder_callbacks_);
  }

  CustomHeaderInjectionConfigSharedPtr config_;
  std::shared_ptr<CustomHeaderInjectionFilter> filter_;
  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
};

/**
 * Test that request headers are injected correctly.
 */
TEST_F(CustomHeaderInjectionTest, InjectRequestHeaders) {
  const std::string request_config = R"EOF(
headers:
  - header_name: X-Custom-Header
    header_value: custom-value
    inject_in_request: true
    inject_in_response: false
)EOF";

  initializeFilter(request_config);

  Http::TestRequestHeaderMapImpl incoming_headers{};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(incoming_headers, false));
  EXPECT_EQ("custom-value", incoming_headers.get_("x-custom-header"));
}

/**
 * Test that response headers are injected correctly.
 */
TEST_F(CustomHeaderInjectionTest, InjectResponseHeaders) {
  const std::string response_config = R"EOF(
headers:
  - header_name: X-Response-Header
    header_value: response-value
    inject_in_request: false
    inject_in_response: true
)EOF";

  initializeFilter(response_config);

  Http::TestResponseHeaderMapImpl incoming_headers{};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(incoming_headers, false));
  EXPECT_EQ("response-value", incoming_headers.get_("x-response-header"));
}

/**
 * Test that headers are injected in both request and response.
 */
TEST_F(CustomHeaderInjectionTest, InjectBothHeaders) {
  const std::string both_config = R"EOF(
headers:
  - header_name: X-Both-Header
    header_value: both-value
    inject_in_request: true
    inject_in_response: true
)EOF";

  initializeFilter(both_config);

  Http::TestRequestHeaderMapImpl request_headers{};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, false));
  EXPECT_EQ("both-value", request_headers.get_("x-both-header"));

  Http::TestResponseHeaderMapImpl response_headers{};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(response_headers, false));
  EXPECT_EQ("both-value", response_headers.get_("x-both-header"));
}

/**
 * Test with multiple headers.
 */
TEST_F(CustomHeaderInjectionTest, MultipleHeaders) {
  const std::string multi_config = R"EOF(
headers:
  - header_name: X-Header-1
    header_value: value1
    inject_in_request: true
    inject_in_response: false
  - header_name: X-Header-2
    header_value: value2
    inject_in_request: false
    inject_in_response: true
  - header_name: X-Header-3
    header_value: value3
    inject_in_request: true
    inject_in_response: true
)EOF";

  initializeFilter(multi_config);

  Http::TestRequestHeaderMapImpl request_headers{};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, false));
  EXPECT_EQ("value1", request_headers.get_("x-header-1"));
  EXPECT_EQ("value3", request_headers.get_("x-header-3"));

  Http::TestResponseHeaderMapImpl response_headers{};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(response_headers, false));
  EXPECT_EQ("value2", response_headers.get_("x-header-2"));
  EXPECT_EQ("value3", response_headers.get_("x-header-3"));
}

} // namespace
} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

